/**
 * The AkmeEngine
 * 
 * "akmД“" - Greek for point, edge, highest degree
 * The engine that knows when to stop to go further.
 */

import type {
  Suspension,
  WaitingQuestion,
  Threshold,
  ThresholdType,
  Resolution,
  AkmeConfig,
  Timing,
} from './types.js';
import { DEFAULT_AKME_CONFIG } from './types.js';

export class AkmeEngine {
  private suspensions: Map<string, Suspension> = new Map();
  private questions: Map<string, WaitingQuestion> = new Map();
  private config: AkmeConfig;
  private resolvedSuspensions: Resolution[] = [];

  constructor(config: Partial<AkmeConfig> = {}) {
    this.config = { ...DEFAULT_AKME_CONFIG, ...config };
  }

  detectThreshold(context: string, indicators: string[]): Threshold | null {
    const detectedType = this.matchToThreshold(context, indicators);
    if (!detectedType || !this.config.triggerThresholds.includes(detectedType)) {
      return null;
    }

    const confidence = this.calculateConfidence(context, indicators, detectedType);

    return {
      type: detectedType,
      detectedAt: Date.now(),
      confidence,
      indicators,
      suggestedAction: this.suggestAction(detectedType, confidence),
    };
  }

  suspend(
    reason: string,
    thresholdType: ThresholdType,
    questions: WaitingQuestion[],
    context: Suspension['context']
  ): Suspension {
    if (this.suspensions.size >= this.config.maxSuspensions) {
      throw new Error(`Maximum suspensions reached (${this.config.maxSuspensions})`);
    }

    const suspension: Suspension = {
      id: `susp_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
      startedAt: Date.now(),
      reason,
      thresholdType,
      questions,
      context,
      notes: [],
    };

    this.suspensions.set(suspension.id, suspension);

    for (const q of questions) {
      this.questions.set(q.id, q);
    }

    return suspension;
  }

  addNote(suspensionId: string, note: string): void {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) throw new Error(`Suspension not found: ${suspensionId}`);
    suspension.notes.push(`[${new Date().toISOString()}] ${note}`);
  }

  calculateTiming(suspension: Suspension): Timing {
    const heldDuration = Date.now() - suspension.startedAt;
    const base = this.config.minHoldTime;
    const multiplier = suspension.questions.length * 0.5;

    const additionalTime = Math.min(heldDuration * multiplier, 300000);

    return {
      optimalResume: Date.now() + Math.max(base - heldDuration, 30000),
      factors: [
        `Base hold: ${base}ms`,
        `Question load: ${suspension.questions.length}`,
        `Threshold type: ${suspension.thresholdType}`,
        `Already held: ${heldDuration}ms`,
      ],
    };
  }

  resolve(suspensionId: string, trigger: Resolution['trigger'], insight?: string): Resolution {
    const suspension = this.suspensions.get(suspensionId);

export type ThresholdType =
  | 'complexity' // Code too complex to continue blindly
  | 'uncertainty' // Multiple valid paths, no clear winner
  | 'saturation' // Cognitive or information overload
  | 'intuition' // Something feels missing, can't articulate
  | 'transition' // Phase shift in understanding required
  | 'emergence' // Waiting for pattern to crystallize
  | 'arrival'; // The threshold of becoming-present

export type Urgency = 'immediate' | 'soon' | 'when-ready' | 'eventually';

export interface WaitingQuestion {
  id: string;
  question: string;
  context: string;
  thresholdType: ThresholdType;
  urgency: Urgency;
  createdAt: number;
  catalysts: string[]; // What might resolve this
  blockers: string[]; // What's preventing resolution
}

export interface Suspension {
  id: string;
  startedAt: number;
  reason: string;
  thresholdType: ThresholdType;
  questions: WaitingQuestion[];
  context: {
    file: string;
    line?: number;
    surrounding?: string;
  };
  notes: string[];
}

export interface Threshold {
  type: ThresholdType;
  detectedAt: number;
  confidence: number; // 0-1
  indicators: string[];
  suggestedAction: 'hold' | 'explore' | 'proceed' | 'simplify';
}

export interface AkmeConfig {
  maxSuspensions: number; // How many open suspensions allowed
  triggerThresholds: ThresholdType[]; // Which types to auto-detect
  minHoldTime: number; // Minimum milliseconds to hold
  autoResolve: boolean; // Auto-resolve on pattern match
}

export const DEFAULT_AKME_CONFIG: AkmeConfig = {
  maxSuspensions: 5,
  triggerThresholds: ['complexity', 'uncertainty', 'intuition', 'saturation'],
  minHoldTime: 60000, // 1 minute minimum hold
  autoResolve: false,
};

export interface Timing {
  optimalResume: number; // When to check back
  factors: string[]; // What determines timing
}

export interface Resolution {
  suspensionId: string;
  resolvedAt: number;
  trigger: 'manual' | 'pattern-match' | 'time-elapsed' | 'insight';

/**
 * Semantic Pathfinder for Memory Palace
 * 
 * Navigate by meaning, not just coordinates.
 * Discover paths through the palace using semantic similarity,
 * generating poetic descriptions of the journey.
 */

import type { PalaceRoom } from './MemoryPalace';

export interface SemanticEdge {
  from: string;
  to: string;
  weight: number; // 0-1, higher = more similar
  sharedConcepts: string[];
  connectionType: 'direct' | 'semantic' | 'thematic' | 'temporal';
}

export interface SemanticPath {
  rooms: PalaceRoom[];
  edges: SemanticEdge[];
  totalDistance: number;
  coherence: number; // How semantically coherent the path is
  poeticDescription: string;
}

export interface PathQuery {
  from: string;
  to: string;
  preferredMood?: PalaceRoom['texture']['mood'];
  avoidThemes?: string[];
  maxLength?: number;
}

export interface SemanticNode {
  room: PalaceRoom;
  edges: SemanticEdge[];
  visited: boolean;
  distance: number;
  previous: string | null;
}

export type SimilarityFunction = (a: string[], b: string[]) => number;

/**
 * Extract meaningful words from text
 */
export function extractWords(text: string): string[] {
  return text
    .toLowerCase()
    .split(/[\s\W_]+/)
    .filter(w => w.length > 2 && !isStopWord(w));
}

/**
 * Common stop words to filter out
 */
function isStopWord(word: string): boolean {
  const stopWords = new Set([
    'the', 'and', 'for', 'are', 'but', 'not', 'you', 'all', 'can', 'had', 'her', 'was',
    'one', 'our', 'out', 'day', 'get', 'has', 'him', 'his', 'how', 'its', 'may', 'new',
