// GeoArt - Shape Plotter Application
class GeoArt {
    constructor() {
        this.shapes = [];
        this.selectedShape = null;
        this.currentTool = 'select';
        this.isDragging = false;
        this.dragStart = { x: 0, y: 0 };
        this.history = [];
        this.shapeIdCounter = 0;

        this.canvas = document.getElementById('canvas');
        this.shapesContainer = document.getElementById('shapes-container');
        this.propertiesPanel = document.getElementById('properties-panel');

        this.init();
    }

    init() {
        this.setupEventListeners();
        this.resizeCanvas();
        window.addEventListener('resize', () => this.resizeCanvas());
    }

    resizeCanvas() {
        const container = this.canvas.parentElement;
        this.canvas.setAttribute('width', container.clientWidth);
        this.canvas.setAttribute('height', container.clientHeight);
    }

    setupEventListeners() {
        // Tool selection
        document.querySelectorAll('.tool-btn').forEach(btn => {
            btn.addEventListener('click', () => this.setTool(btn.dataset.tool));
        });

        // Canvas events
        this.canvas.addEventListener('mousedown', (e) => this.handleMouseDown(e));
        this.canvas.addEventListener('mousemove', (e) => this.handleMouseMove(e));
        this.canvas.addEventListener('mouseup', (e) => this.handleMouseUp(e));

        // Keyboard shortcuts
        document.addEventListener('keydown', (e) => {
            if (e.ctrlKey && e.key === 'z') this.undo();
            if (e.key === 'Delete' && this.selectedShape) this.deleteShape(this.selectedShape.id);
        });
    }

    setTool(tool) {
        this.currentTool = tool;
        document.querySelectorAll('.tool-btn').forEach(btn => {
            btn.classList.toggle('active', btn.dataset.tool === tool);
        });
        this.canvas.style.cursor = tool === 'select' ? 'default' : 'crosshair';
    }

    getMousePos(e) {
        const rect = this.canvas.getBoundingClientRect();
        return {
            x: e.clientX - rect.left,
            y: e.clientY - rect.top
        };
    }

    handleMouseDown(e) {
        const pos = this.getMousePos(e);

        if (this.currentTool === 'select') {
            const clickedShape = this.getShapeAt(pos);
            if (clickedShape) {
                this.selectShape(clickedShape);
                this.isDragging = true;
                this.dragStart = pos;
            } else {
                this.selectShape(null);
            }
        } else {
            this.createShape(this.currentTool, pos);
        }
    }

    handleMouseMove(e) {
        if (!this.isDragging || !this.selectedShape) return;

        const pos = this.getMousePos(e);
        const dx = pos.x - this.dragStart.x;
        const dy = pos.y - this.dragStart.y;

        this.selectedShape.x += dx;
        this.selectedShape.y += dy;
        this.dragStart = pos;

        this.render();
        this.updatePropertiesPanel();
    }

    handleMouseUp(e) {
        this.isDragging = false;
    }

    getShapeAt(pos) {
        // Check in reverse order (top to bottom)
        for (let i = this.shapes.length - 1; i >= 0; i--) {
            if (this.isPointInShape(pos, this.shapes[i])) {
                return this.shapes[i];
            }
        }
        return null;
    }

    isPointInShape(pos, shape) {
        switch (shape.type) {
            case 'rectangle':
                return pos.x >= shape.x && pos.x <= shape.x + shape.width &&
                       pos.y >= shape.y && pos.y <= shape.y + shape.height;
            case 'circle':
                const dx = pos.x - (shape.x + shape.radius);
                const dy = pos.y - (shape.y + shape.radius);
                return Math.sqrt(dx * dx + dy * dy) <= shape.radius;
            case 'polygon':
                return this.isPointInPolygon(pos, shape.points);
            case 'line':
                return this.isPointNearLine(pos, shape);
            default:
                return false;
        }
    }

    isPointInPolygon(pos, points) {
        let inside = false;
        for (let i = 0, j = points.length - 1; i < points.length; j = i++) {
            const xi = points[i].x + this.shapes.find(s => s.points === points)?.x || 0;
            const yi = points[i].y + this.shapes.find(s => s.points === points)?.y || 0;
            const xj = points[j].x + this.shapes.find(s => s.points === points)?.x || 0;
            const yj = points[j].y + this.shapes.find(s => s.points === points)?.y || 0;

            const intersect = ((yi > pos.y) !== (yj > pos.y)) &&
                (pos.x < (xj - xi) * (pos.y - yi) / (yj - yi) + xi);
            if (intersect) inside = !inside;
        }
        return inside;
    }

    isPointNearLine(pos, line) {
        // Distance from point to line segment
        const x1 = line.x, y1 = line.y;
        const x2 = line.x2, y2 = line.y2;
        const A = pos.x - x1, B = pos.y - y1;
        const C = x2 - x1, D = y2 - y1;
        const dot = A * C + B * D;
        const lenSq = C * C + D * D;
        let param = dot / lenSq;
        let xx, yy;
        if (lenSq === 0 || param < 0 || (param > 1 && Math.abs(param - 1) > 0.01)) return false;
        if (param > 1) { xx = x2; yy = y2; }
        else { xx = x1 + param * C; yy = y1 + param * D; }
        const dx = pos.x - xx;
        const dy = pos.y - yy;
        return Math.sqrt(dx * dx + dy * dy) < 5;
    }

    createShape(type, pos) {
        this.saveState();
        const id = `shape_${++this.shapeIdCounter}`;
        let shape = {
            id,
            type,
            fill: '#3498db',
            stroke: '#2980b9',
            strokeWidth: 2,
            opacity: 1
        };

        switch (type) {
            case 'rectangle':
                shape.x = pos.x - 50;
                shape.y = pos.y - 35;
                shape.width = 100;
                shape.height = 70;
                shape.rx = 0;
                break;
            case 'circle':
                shape.x = pos.x - 50;
                shape.y = pos.y - 50;
                shape.radius = 50;
                break;
            case 'polygon':
                shape.x = pos.x - 60;
                shape.y = pos.y - 60;
                shape.points = [
                    { x: 60, y: 0 },
                    { x: 120, y: 40 },
                    { x: 100, y: 100 },
                    { x: 20, y: 100 },
                    { x: 0, y: 40 }
                ];
                break;
            case 'line':
                shape.x = pos.x;
                shape.y = pos.y;
                shape.x2 = pos.x + 100;
                shape.y2 = pos.y;
                shape.fill = 'none';
                break;
        }

        this.shapes.push(shape);
        this.render();
        this.selectShape(shape);
    }

    selectShape(shape) {
        this.selectedShape = shape;
        this.render();
        this.updatePropertiesPanel();
    }

    deleteShape(id) {
        this.saveState();
        this.shapes = this.shapes.filter(s => s.id !== id);
        if (this.selectedShape?.id === id) this.selectedShape = null;
        this.render();
        this.updatePropertiesPanel();
    }

    updateShape(id, updates) {
        const shape = this.shapes.find(s => s.id === id);
        if (shape) {
            Object.assign(shape, updates);
            this.render();
        }
    }

    updatePropertiesPanel() {
        if (!this.selectedShape) {
            this.propertiesPanel.innerHTML = '<p style="color: #666; text-align: center;">Select a shape</p>';
            return;
        }

        const shape = this.selectedShape;
        const isLine = shape.type === 'line';

        this.propertiesPanel.innerHTML = `
            <h3>${shape.type.charAt(0).toUpperCase() + shape.type.slice(1)}</h3>
            <div style="margin: 1rem 0;">
                <label>Position</label><br>
                X: <input type="number" value="${shape.x}" onchange="geoArt.updateShape('${shape.id}', {x: parseFloat(this.value)})" style="width: 60px;"><br>
                Y: <input type="number" value="${shape.y}" onchange="geoArt.updateShape('${shape.id}', {y: parseFloat(this.value)})" style="width: 60px;">
            </div>
            ${!isLine ? `
            <div style="margin: 1rem 0;">
                <label>Fill Color</label><br>
                <input type="color" value="${shape.fill}" onchange="geoArt.updateShape('${shape.id}', {fill: this.value})">
            </div>` : ''}
            <div style="margin: 1rem 0;">
                <label>Stroke Color</label><br>
                <input type="color" value="${shape.stroke}" onchange="geoArt.updateShape('${shape.id}', {stroke: this.value})">
            </div>
            <div style="margin: 1rem 0;">
                <label>Stroke Width: ${shape.strokeWidth}</label><br>
                <input type="range" min="0" max="10" value="${shape.strokeWidth}" 
                       onchange="geoArt.updateShape('${shape.id}', {strokeWidth: parseInt(this.value)})">
            </div>
            <div style="margin: 1rem 0;">
                <label>Opacity: ${shape.opacity}</label><br>
                <input type="range" min="0" max="1" step="0.1" value="${shape.opacity}" 
                       onchange="geoArt.updateShape('${shape.id}', {opacity: parseFloat(this.value)})">
            </div>
            ${this.getShapeSpecificControls(shape)}
            <button onclick="geoArt.deleteShape('${shape.id}')" style="background: #e74c3c; color: white; border: none; padding: 0.5rem; border-radius: 4px; cursor: pointer; width: 100%;">Delete</button>
        `;
    }

    getShapeSpecificControls(shape) {
        switch (shape.type) {
            case 'rectangle':
                return `
                    <div style="margin: 1rem 0;">
                        <label>Size</label><br>
                        W: <input type="number" value="${shape.width}" onchange="geoArt.updateShape('${shape.id}', {width: parseFloat(this.value)})" style="width: 60px;"><br>
                        H: <input type="number" value="${shape.height}" onchange="geoArt.updateShape('${shape.id}', {height: parseFloat(this.value)})" style="width: 60px;"><br>
                        Radius: <input type="number" value="${shape.rx}" onchange="geoArt.updateShape('${shape.id}', {rx: parseFloat(this.value)})" style="width: 60px;">
                    </div>`;
            case 'circle':
                return `
                    <div style="margin: 1rem 0;">
                        <label>Radius: ${shape.radius}</label><br>
                        <input type="range" min="5" max="200" value="${shape.radius}" 
                               onchange="geoArt.updateShape('${shape.id}', {radius: parseInt(this.value)})">
                    </div>`;
            case 'line':
                return `
                    <div style="margin: 1rem 0;">
                        <label>End Point</label><br>
                        X2: <input type="number" value="${shape.x2}" onchange="geoArt.updateShape('${shape.id}', {x2: parseFloat(this.value)})" style="width: 60px;"><br>
                        Y2: <input type="number" value="${shape.y2}" onchange="geoArt.updateShape('${shape.id}', {y2: parseFloat(this.value)})" style="width: 60px;">
                    </div>`;
            default:
                return '';
        }
    }

    render() {
        this.shapesContainer.innerHTML = this.shapes.map(shape => this.shapeToSVG(shape)).join('');
    }

    shapeToSVG(shape) {
        const isSelected = this.selectedShape?.id === shape.id;
        const selectedClass = isSelected ? 'selected' : '';
        const opacity = shape.opacity !== undefined ? shape.opacity : 1;

        switch (shape.type) {
            case 'rectangle':
                return `<rect id="${shape.id}" class="shape ${selectedClass}" x="${shape.x}" y="${shape.y}" 
                        width="${shape.width}" height="${shape.height}" rx="${shape.rx || 0}"
                        fill="${shape.fill}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}"
                        opacity="${opacity}" onclick="geoArt.selectShape(geoArt.shapes.find(s => s.id === '${shape.id}'))"/>`;
            case 'circle':
                const cx = shape.x + shape.radius;
                const cy = shape.y + shape.radius;
                return `<circle id="${shape.id}" class="shape ${selectedClass}" cx="${cx}" cy="${cy}" r="${shape.radius}"
                        fill="${shape.fill}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}"
                        opacity="${opacity}" onclick="geoArt.selectShape(geoArt.shapes.find(s => s.id === '${shape.id}'))"/>`;
            case 'polygon':
                const points = shape.points.map(p => `${shape.x + p.x},${shape.y + p.y}`).join(' ');
                return `<polygon id="${shape.id}" class="shape ${selectedClass}" points="${points}"
                        fill="${shape.fill}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}"
                        opacity="${opacity}" onclick="geoArt.selectShape(geoArt.shapes.find(s => s.id === '${shape.id}'))"/>`;
            case 'line':
                return `<line id="${shape.id}" class="shape ${selectedClass}" x1="${shape.x}" y1="${shape.y}" 
                        x2="${shape.x2}" y2="${shape.y2}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}"
                        opacity="${opacity}" onclick="geoArt.selectShape(geoArt.shapes.find(s => s.id === '${shape.id}'))"/>`;
            default:
                return '';
        }
    }

    saveState() {
        this.history.push(JSON.parse(JSON.stringify(this.shapes)));
        if (this.history.length > 20) this.history.shift();
    }

    undo() {
        if (this.history.length > 0) {
            this.shapes = this.history.pop();
            this.selectedShape = null;
            this.render();
            this.updatePropertiesPanel();
        }
    }

    clearAll() {
        this.saveState();
        this.shapes = [];
        this.selectedShape = null;
        this.render();
        this.updatePropertiesPanel();
    }

    exportSVG() {
        const width = this.canvas.getAttribute('width');
        const height = this.canvas.getAttribute('height');
        const shapesSVG = this.shapes.map(shape => this.shapeToSVGForExport(shape)).join('\n  ');

        const svgContent = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <defs>
    <!-- Exported from GeoArt -->
  </defs>
  ${shapesSVG}
</svg>`;

        const blob = new Blob([svgContent], { type: 'image/svg+xml' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `geoart_export_${Date.now()}.svg`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    shapeToSVGForExport(shape) {
        const opacity = shape.opacity !== undefined ? shape.opacity : 1;

        switch (shape.type) {
            case 'rectangle':
                return `<rect x="${shape.x}" y="${shape.y}" width="${shape.width}" height="${shape.height}" rx="${shape.rx || 0}"
                        fill="${shape.fill}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}" opacity="${opacity}"/>`;
            case 'circle':
                const cx = shape.x + shape.radius;
                const cy = shape.y + shape.radius;
                return `<circle cx="${cx}" cy="${cy}" r="${shape.radius}"
                        fill="${shape.fill}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}" opacity="${opacity}"/>`;
            case 'polygon':
                const points = shape.points.map(p => `${shape.x + p.x},${shape.y + p.y}`).join(' ');
                return `<polygon points="${points}"
                        fill="${shape.fill}" stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}" opacity="${opacity}"/>`;
            case 'line':
                return `<line x1="${shape.x}" y1="${shape.y}" x2="${shape.x2}" y2="${shape.y2}"
                        stroke="${shape.stroke}" stroke-width="${shape.strokeWidth}" opacity="${opacity}"/>`;
            default:
                return '';
        }
    }
}

// Global instance
