            const rect = container.getBoundingClientRect();
            this.canvas.setAttribute('width', rect.width);
            this.canvas.setAttribute('height', rect.height);
            this.canvas.setAttribute('viewBox', `0 0 ${rect.width} ${rect.height}`);
        };
        resize();
        window.addEventListener('resize', resize);
    }

    setupEvents() {
        // Canvas events
        this.canvas.addEventListener('mousedown', (e) => this.onMouseDown(e));
        this.canvas.addEventListener('mousemove', (e) => this.onMouseMove(e));
        this.canvas.addEventListener('mouseup', (e) => this.onMouseUp(e));

        // Keyboard shortcuts
        document.addEventListener('keydown', (e) => {
            if (e.ctrlKey && e.key === 'z') this.undo();
            if (e.key === 'Delete' && this.selectedId) this.deleteShape(this.selectedId);
        });
    }

    getMousePos(e) {
        const rect = this.canvas.getBoundingClientRect();
        return {
            x: e.clientX - rect.left,
            y: e.clientY - rect.top
        };
    }

    setTool(tool) {
        this.currentTool = tool;
        document.querySelectorAll('.shape-btn').forEach(btn => {
            btn.classList.toggle('active', btn.dataset.tool === tool);
        });
    }

    onMouseDown(e) {
        const pos = this.getMousePos(e);

        if (this.currentTool === 'select') {
            // Check for resize handle first
            const handle = e.target.closest('.resize-handle');
            if (handle) {
                this.isResizing = true;
                this.resizeHandle = handle.dataset.handle;
                this.dragStart = pos;
                return;
            }

            // Check for shape selection
            const shapeEl = e.target.closest('.shape');
            if (shapeEl) {
                this.selectShape(shapeEl.dataset.id);
                this.isDragging = true;
                this.dragStart = pos;
            } else {
                this.selectShape(null);
            }
        } else {
            this.createShape(this.currentTool, pos);
        }
    }

    onMouseMove(e) {
        if (!this.isDragging && !this.isResizing) return;

        const pos = this.getMousePos(e);
        const dx = pos.x - this.dragStart.x;
        const dy = pos.y - this.dragStart.y;

        if (this.isDragging && this.selectedId) {
            const shape = this.getShape(this.selectedId);
            if (shape) {
                shape.x += dx;
                shape.y += dy;
