                const ecx = shape.x + shape.rx;
                const ecy = shape.y + shape.ry;
                svg = `<ellipse class="shape ${isSelected ? 'selected' : ''}" data-id="${shape.id}"
                               cx="${ecx}" cy="${ecy}" rx="${shape.rx}" ry="${shape.ry}" ${style}/>`;
                if (isSelected) {
                    svg += renderHandle(ecx + shape.rx * 0.7, ecy + shape.ry * 0.7, 'se');
