                const max = Math.max(...hist);
                ctx.fillStyle = ['#ff000044', '#00ff0044', '#0000ff44'][ci];

                const barW = canvas.width / hist.length;
                hist.forEach((v, j) => {
                    const h = (v / max) * 80;
                    ctx.fillRect(j * barW, 100 - h, barW - 0.5, h);
                });
            });

